import React, { useState } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import styled from "styled-components";

import Logo from "../../assets/poll-logo.png";
import ThunderIcon from "../../assets/thunder.png";
import SearchIcon from "../../assets/search.png";
import WhitePollIcon from "../../assets/WhitePollIcon.png";
import Modal from "../Modal";

const Header = () => {
  const [isOpen, toggle] = useState(false);

  function handlOpenModal(open) {
    console.log("close modal");
    toggle(open);
  }

  return (
    <>
      <div className="navbar">
        <div className="container">
          <div className="navWrapper">
            <Link to="/" style={{ textDecoration: "none" }}>
              <div className="navContent">
                <img src={Logo} alt="Logo" className="logo" />
                <img src={WhitePollIcon} alt="Logo" className="mobLogo" />

                <h2>PollHole</h2>
              </div>
            </Link>

            <div className="navContent">
              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => handlOpenModal(true)}
                className="createPool"
              >
                Create Poll
                <img src={ThunderIcon} alt="Thunder" />
              </motion.button>
            </div>

            {/* <div className="navContent">
            <img src={SearchIcon} alt="Search" style={{ cursor: "pointer" }} />
            <button className="login">Login</button>
          </div> */}
          </div>
        </div>
      </div>

      <Modal isOpen={isOpen} handleClose={() => handlOpenModal(false)}>
        <ModalContent>
          <h1> Coming Soon </h1>
        </ModalContent>
      </Modal>
    </>
  );
};

export default Header;

const ModalContent = styled.div`
  height: 100%;
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  h1 {
    font-style: normal;
    font-weight: 800;
    font-size: 76px;
    line-height: 86px;
    background: linear-gradient(90deg, #4bd97e 0%, #16fd72 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    text-align: center;
  }

  @media (max-width: 768px) {
    h1 {
      font-size: 56px;
      line-height: 66px;
    }
  }

  @media (max-width: 480px) {
    h1 {
      font-size: 36px;
      line-height: 46px;
    }
  }
`;
