import React from "react";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import LikeIcon from "../../assets/svg/thumb_up_black_24dp.svg";
import UnlikeIcon from "../../assets/svg/BlackUnlike.svg";
import RedUnlike from "../../assets/svg/thumb_down_black_24dp.svg";
import BLike from "../../assets/svg/LikeGrey.svg";
import { Link } from "react-router-dom";

const user = localStorage.getItem("user");
const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
const numberOfPollLiked = localStorage.getItem("numberOfPollLiked");

const SinglePollContainer = (props) => {
  const { val, onVote,banner_image } = { ...props };
  const { slug } = useParams();
  let navigate = useNavigate();
  const likePoll = async (liked_poll, is_like) => {
    // one user can do 10 poll like or dislike
    if (parseInt(numberOfPollLiked, 10) > 11) {
      navigate("/login");
    } else {
      let param;
      if (user) {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          userid: JSON.parse(user)._id,
        };
      } else {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          guest_user_id: GUEST_USER_ID,
        };
      }
      try {
        var res = await POST(APIs.LIKEUPDATE, param);
        if (res.status === 200) {
          onVote();
          if (!user) {
            const value = parseInt(numberOfPollLiked, 10);
            localStorage.setItem("numberOfPollLiked", value + 1);
          }
        } else {
          console.log(res.msg);
        }
      } catch (error) {
        console.log(error);
      }
    }
  };

  const handleSharing = (question, url) => {
    if (navigator.share) {
      try {
        navigator
          .share({
            title: "The Poll App",
            text: question,
            url: url,
          })
          .then(() => console.log("Success"));
      } catch (error) {
        console.log(`Oops! I couldn't share to the world because: ${error}`);
      }
    } else {
      // fallback code
      console.log(
        "Web share is currently not supported on this browser. Please provide a callback"
      );
    }
  };
  
  return (
    <>
    { val.question_type === 3 ? (
        <div className="personPollCard">
          <div className="row">
            <div className="col">
              <img src={banner_image} alt="og_imsge" className="personImg" />
              <div className="bottomLeft">
                <p className="percent">{val.likes_per === "" ? 0 : val.likes_per}%</p>
              </div>
            </div>
            <div className="col">
              <div className="topRight">{val.tags[0].tag_name}</div>
              <div className="pollCarouselContent">
                <div className="flex">
                  <Link style={{ textDecoration: "none", color: "#223350" }} to={val.slug}>
                    <h4 className="personName">{val.question}</h4>
                  </Link>
                </div>
                <div className="flex likeUnlike">
                  <div
                    className="flex"
                    onClick={() => (val.isLiked ? null : likePoll(val._id, true))}
                    style={{ cursor: "pointer" }}
                  >
                    <img src={val.isLiked ? LikeIcon : BLike} alt="Like" width={50} height={50} />
                  </div>
                  <div
                    className="flex"
                    onClick={() => (val.isDisliked ? null : likePoll(val._id, false))}
                    style={{ cursor: "pointer" }}
                  >
                    <img
                      src={val.isDisliked ? RedUnlike : UnlikeIcon}
                      alt="Unlike"
                      width={50}
                      height={50}
                    />
                  </div>
                </div>
                <div className="flex">
                  <span className="ttleVoteCOunt">{val.likes_count + val.dislikes_count}</span>
                  <h6 className="ttlVote">Total Votes</h6>
                </div>
                <div className="flex">
                  <button
                    className="shareBtn"
                    onClick={() => handleSharing(val.question, val.slug)}
                  >
                    Share
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
    ):null}
      {/* {val.question_type === 3 ? (
          <div className="row pollRow">
            <div className="col">
              <>
                <div className="heading">
                  {slug !== undefined ? (
                    <div className="flex">
                      <h2>{val.question}</h2>
                      <h1>{val.likes_per}%</h1>
                    </div>
                  ) : (
                    <Link
                      style={{ textDecoration: "none", color: "#223350" }}
                      to={val.slug}
                    >
                      <div className="flex">
                        <h2>{val.question}</h2>
                        {val.isLiked > 0 || val.dislikes_count > 0 ? (
                          <h1>{val.likes_per}%</h1>
                        ) : null}
                      </div>
                    </Link>
                  )}

                  {val.question_type === 3 ? (
                    <div style={{ display: "flex", columnGap: "10px" }}>
                      {val.tags.map((tag, index) => {
                        return <div className="tag">{tag.tag_name}</div>;
                      })}
                    </div>
                  ) : null}
                </div>

                {val.question_type === 3 ? (
                  <div className="row">
                    <div className="col-1">
                      <SinglePoll data={val.answers} />

                      <div className="LikeWrapper">
                        <div
                          className="flex"
                          onClick={() =>
                            val.isLiked ? null : likePoll(val._id, true)
                          }
                          style={{ cursor: "pointer" }}
                        >
                          <img
                            src={val.isLiked ? LikeIcon : BLike}
                            alt="Like"
                          />

                          <h4>{val.likes_count}</h4>
                        </div>
                        <div
                          className="flex"
                          onClick={() =>
                            val.isDisliked ? null : likePoll(val._id, false)
                          }
                          style={{ cursor: "pointer" }}
                        >
                          <img
                            src={val.isDisliked ? RedUnlike : UnlikeIcon}
                            alt="Unlike"
                          />
                          <h4>{val.dislikes_count}</h4>
                        </div>
                      </div>
                    </div>
                    <div className="col-1">
                      <div className="voteWrapper">
                        <h1>{val.likes_count + val.dislikes_count}</h1>
                        <h2>Votes</h2>
                        <div className="border" />
                        <h3>Share</h3>
                        <div className="socialDiv">
                          <img src={TwitterIcon} alt="Twitter" />
                          <h3>Twitter</h3>
                        </div>
                        <div className="socialDiv">
                          <img src={FacebookIcon} alt="Facebook" />
                          <h3 style={{ color: "#0F5DA1" }}>Facebook</h3>
                        </div>
                        <div className="socialDiv">
                          <img src={WhatsappIcon} alt="Whatsapp" />
                          <h3 style={{ color: "#40C351" }}>Whatsapp</h3>
                        </div>
                        <div className="socialDiv">
                          <img src={LinkIcon} alt="Link" />
                          <h3 style={{ color: "#FE7A00" }}>Copy Link</h3>
                        </div>

                        <div className="reportBtn">
                          <button>Report abuse</button>
                        </div>
                      </div>
                    </div>
                  </div>
                ) : null}
              </>
            </div>
          </div>
        ) : null} */}
    </>
  );
};

export default SinglePollContainer;
