import React from "react";
import ProgressBar from "@ramonak/react-progress-bar";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import { useNavigate } from "react-router-dom";

const ImagePoll = (props) => {
  const { data, question_id, isVoted, answers, onVote } = { ...props };
  const user = localStorage.getItem("user");
  const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
  const numberOfPollVoted = localStorage.getItem("numberOfPollVoted");
  let navigate = useNavigate();
  const submitPoll = async (question_id, answer_id) => {
    if (parseInt(numberOfPollVoted, 10) > 2) {
      navigate("/login");
    } else {
      let param;
      if (user) {
        param = {
          question_id: question_id,
          answers: answer_id,
          user_id: JSON.parse(user)._id,
        };
      } else {
        param = {
          question_id: question_id,
          answers: answer_id,
          guest_user_id: GUEST_USER_ID,
        };
      }
      try {
        var res = await POST(APIs.ADDANSWER, param);
        //    onVote();

        if (res.status === 200) {
          if (!user) {
            const value = parseInt(numberOfPollVoted, 10);
            localStorage.setItem("numberOfPollVoted", value + 1);
          }
          if (typeof onVote == "function") {
            onVote();
          }
        } else {
          console.log(res.msg);
        }
      } catch (error) {
        console.log(error);
      }
    }
  };

  return (
    <>
      {data.map((val, index) => {
        console.log(val, val.MyVote, "From Image Poll");

        return (
          <div
            className="card"
            key={index}
            style={{ border: val.isVoted ? "1px solid red" : null }}
          >
            <div onClick={() => submitPoll(question_id, val._id)}>
              <img src={val.image} alt={val.text} width="100%" height="200px" />
              <div className="cardContent">
                <h1>{val.text}</h1>

                {isVoted ? (
                  val.vote_per >= 75 ? (
                    <ProgressBar
                      completed={val.vote_per}
                      isLabelVisible={false}
                      className="lineBar"
                      animateOnRender={true}
                      initCompletedOnAnimation={0}
                      transitionDuration="5s"
                      baseBgColor="#ffdddd"
                      bgColor="linear-gradient(180deg, #bf3e3e 0%, #f95e5e 100%)"
                      borderRadius="10px"
                      height="7px"
                    />
                  ) : data.MyVote === true || val.vote_per >= 50 ? (
                    <ProgressBar
                      completed={val.vote_per}
                      isLabelVisible={false}
                      className="lineBar"
                      animateOnRender={true}
                      initCompletedOnAnimation={0}
                      transitionDuration="5s"
                      baseBgColor={data.MyVote === true ? "rgba(75, 217, 126, 0.22)" : "#ddf7ff"}
                      bgColor={
                        data.MyVote === true
                          ? "linear-gradient(180deg, #4BD97E 0%, #68EF98 100%)"
                          : "linear-gradient(180deg, #3e81bf 0%, #5eaff9 100%)"
                      }
                      borderRadius="10px"
                      height="7px"
                    />
                  ) : val.vote_per >= 25 ? (
                    <ProgressBar
                      completed={val.vote_per}
                      isLabelVisible={false}
                      className="lineBar"
                      animateOnRender={true}
                      initCompletedOnAnimation={0}
                      transitionDuration="5s"
                      baseBgColor="#f8ddff"
                      bgColor="linear-gradient(180deg, #bf3eb2 0%, #f65ef9 100%)"
                      borderRadius="10px"
                      height="7px"
                    />
                  ) : (
                    <ProgressBar
                      completed={val.vote_per}
                      isLabelVisible={false}
                      className="lineBar"
                      animateOnRender={true}
                      initCompletedOnAnimation={0}
                      transitionDuration="5s"
                      baseBgColor="#ecffdd"
                      bgColor="linear-gradient(180deg, #bdbf3e 0%, #e3f95e 100%)"
                      borderRadius="10px"
                      height="7px"
                    />
                  )
                ) : null}

                {isVoted ? (
                  <div className="progress">
                    <span>{val.vote_per} Vote</span>
                    <b>{val.vote_per}%</b>
                  </div>
                ) : null}
                {/* <div className="progress">
                  <span>{val.vote_per} Vote</span>
                  <b>{val.vote_per}%</b>
                </div> */}
              </div>
            </div>
          </div>
        );
      })}
    </>
  );
};

export default ImagePoll;
