import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import { AiFillHome } from "react-icons/ai";

import CardPoll from "../CardPoll";
import ImagePoll from "../ImagePoll";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import LikeIcon from "../../assets/svg/thumb_up_black_24dp.svg";
import UnlikeIcon from "../../assets/UnLike.png";
import RedUnlike from "../../assets/svg/thumb_down_black_24dp.svg";
import BLike from "../../assets/Blike.png";

const user = localStorage.getItem("user");
const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
const numberOfPollLiked = localStorage.getItem("numberOfPollLiked");
const numberOfPollVoted = localStorage.getItem("numberOfPollVoted");
const CardContainer = (props) => {
  const { val, onVote } = props;

  const { slug } = useParams();
  let navigate = useNavigate();
  if (!numberOfPollVoted) {
    localStorage.setItem("numberOfPollVoted", 0);
  }
  if (!numberOfPollLiked) {
    localStorage.setItem("numberOfPollLiked", 0);
  }
  const [compData, setCompData] = useState(val);
  const [answerId, setAnswerId] = useState("");
  const likePoll = async (liked_poll, is_like) => {
    if (parseInt(numberOfPollLiked, 10) > 11) {
      navigate("/login");
    } else {
      let param;
      if (user) {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          userid: JSON.parse(user)._id,
        };
      } else {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          guest_user_id: GUEST_USER_ID,
        };
      }
      try {
        var res = await POST(APIs.LIKEUPDATE, param);
        if (res.status === 200) {
          setCompData((prevData) => ({
            ...prevData,
            ...res.data,
          }));
          if (!user) {
            const compDataue = parseInt(numberOfPollLiked, 10);
            localStorage.setItem("numberOfPollLiked", compDataue + 1);
          }
        } else {
          console.log(res.msg);
        }
      } catch (error) {
        console.log(error);
      }
    }
  };

  const handleSharing = (question, url) => {
    // console.log(url);
    if (navigator.share) {
      try {
        navigator
          .share({
            title: "The Poll App",
            text: question,
            url: url,
          })
          .then(() => console.log("Success"));
      } catch (error) {
        console.log(`Oops! I couldn't share to the world because: ${error}`);
      }
    } else {
      // fallback code
      console.log(
        "Web share is currently not supported on this browser. Please provide a callback"
      );
    }
  };

  const submitPoll = async () => {
    if (parseInt(numberOfPollVoted, 10) > 49) {
      navigate("/login");
    } else {
      let param;
      if (user) {
        param = {
          question_id: compData._id,
          answers: answerId,
          user_id: JSON.parse(user)._id,
        };
      } else {
        param = {
          question_id: compData._id,
          answers: answerId,
          guest_user_id: GUEST_USER_ID,
        };
      }
      try {
        var res = await POST(APIs.ADDANSWER, param);
        if (res.status === 200) {
          setCompData((prevData) => ({
            ...prevData,
            ...res.data,
          }));
          if (!user) {
            const value = parseInt(numberOfPollVoted, 10);
            localStorage.setItem("numberOfPollVoted", value + 1);
          }
        } else {
          console.log(res.msg);
        }
      } catch (error) {
        console.log(error);
      }
    }
  };

  useEffect(() => {
    if (answerId != "") submitPoll();
  }, [answerId]);
  console.log('com data',compData);
  return (
    <>
      <div className="container vote_wrapper">
        <div className="row">
          <div
            className="voteCol1"
            // style={{ display: compData.question_type !== 3 ? "block" : "none" }}
          >
            <div className="pool">
              
                <div className="navWrapper">
                  <div className="flex">
                    <img
                      alt="Icon"
                      src={
                        compData.creater_id.profile_pic !== ""
                          ? compData.creater_id.profile_pic
                          : ""
                      }
                      width={25}
                      height={25}
                      style={{ borderRadius: 50 }}
                    />
                    <h3>{compData.creater_id.name !== "" ? compData.creater_id.name : "User"}</h3>
                  </div>
                </div>
             

              <>
               
                  <div className="heading">
                    {slug !== undefined ? (
                      <div className="flex">
                        <h2>{compData.question}</h2>
                      </div>
                    ) : (
                      <Link style={{ textDecoration: "none", color: "#223350" }} to={compData.slug}>
                        <div className="flex">
                          <h2>{compData.question}</h2>
                        </div>
                      </Link>
                    )}
                  </div>
                

                {
                  compData.question_image === undefined || compData.question_image === "" ? null : (
                    <img
                      src={compData.question_image}
                      alt="question_image"
                      className="question_image"
                    />
                  )
                }

                {compData.question_type === 1 ? (
                  <div className="cardOptions" style={{ gap: 0 }}>
                    {compData.answers.map((compData2, index) => {
                      return (
                        <CardPoll
                          onVote={onVote}
                          question_id={compData._id}
                          data={compData2}
                          key={index}
                          isVoted={compData.isVoted}
                          answers={compData}
                          setAnswerId={setAnswerId}
                        />
                      );
                    })}
                  </div>
                ) : null}
                {compData.question_type === 2 ? (
                  <div className="cardOptions">
                    <ImagePoll
                      data={compData.answers}
                      onVote={onVote}
                      question_id={compData._id}
                      isVoted={compData.isVoted}
                    />
                  </div>
                ) : null}
                {compData.question_type === 3 ? (
                  <div className="cardOptions">
                   <img  style={{width:"100%",minWidth: "100%",objectFit:"cover",height:"100%"}} src={compData.answers[0].image} alt={"Alter"}  />
                  </div>
                ) : null}
              </>

              
                <div className="flex" style={{ justifyContent: "space-between" }}>
                  <div className="LikeWrapper">
                    <h4>{compData.total_vote} Votes</h4>
                    <div
                      className="flex"
                      onClick={() => (compData.isLiked ? null : likePoll(compData._id, true))}
                      style={{ cursor: "pointer" }}
                    >
                      <img
                        src={compData.isLiked ? LikeIcon : BLike}
                        alt="Like"
                        className="likeIcon"
                      />

                      <h4>{compData.likes_count}</h4>
                    </div>
                    <div
                      className="flex"
                      onClick={() => (compData.isDisliked ? null : likePoll(compData._id, false))}
                      style={{ cursor: "pointer" }}
                    >
                      <img src={compData.isDisliked ? RedUnlike : UnlikeIcon} alt="Unlike" />
                      <h4>{compData.dislikes_count}</h4>
                    </div>
                  </div>
                  <div className="flex">
                    <button
                      className="shareBtn"
                      onClick={() => handleSharing(compData.question, compData.slug)}
                    >
                      Share
                    </button>

                    {/* <div
                      onClick={() => handleSharing(compData.question, compData.slug)}
                      style={{ cursor: "pointer" }}
                    >
                      <button
                        className="shareBtn flex"
                        onClick={() => handleSharing(compData.question, compData.slug)}
                      >
                        <AiFillHome />
                        Back to home
                      </button>
                    </div> */}
                  </div>
                </div>
              
            </div>
          </div>
          <div className="voteCol2">
            {compData.question_type !== 3 ? <div className="AdDiv">AD</div> : null}
          </div>
        </div>
      </div>
    </>
  );
};

export default CardContainer;
